"use client";

import { useEffect, useState } from "react";
import { useParams, useRouter } from "next/navigation";
import {
  CheckCircle,
  XCircle,
  ArrowLeft,
  Package,
  User,
  FileText,
  Image as ImageIcon,
  Loader2,
} from "lucide-react";

const BASE_URL = "http://localhost:5000";

const ClaimDetailsPage = () => {
  const { id } = useParams();
  const router = useRouter();

  const [claim, setClaim] = useState(null);
  const [loading, setLoading] = useState(true);
  const [actionLoading, setActionLoading] = useState(false); // ✅ Action loading state
  const [actionResult, setActionResult] = useState(""); // ✅ Success message

  // ================= FETCH CLAIM =================
  useEffect(() => {
    if (!id) return;

    const fetchClaim = async () => {
      try {
        const token = localStorage.getItem("accessToken");
        const res = await fetch(`${BASE_URL}/admin/claim/${id}`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        if (!res.ok) throw new Error("Failed to load claim");
        const data = await res.json();
        setClaim(data);
      } catch (err) {
        console.error("Fetch error:", err);
      } finally {
        setLoading(false);
      }
    };

    fetchClaim();
  }, [id]);

  // ================= ACTION HANDLER =================
  const handleAction = async (endpoint, statusText) => {
    setActionLoading(true);
    setActionResult(""); // Reset previous result
    try {
      const token = localStorage.getItem("accessToken");
      const res = await fetch(`${BASE_URL}/admin/${endpoint}/${id}`, {
        method: "POST",
        headers: { Authorization: `Bearer ${token}` },
      });
      if (!res.ok) throw new Error("Action failed");

      // Update claim status on the page dynamically
      setClaim((prev) => ({ ...prev, status: statusText.toLowerCase() }));
      setActionResult(`Claim ${statusText}`);
    } catch (err) {
      console.error(err);
      setActionResult("Failed to process action");
    } finally {
      setActionLoading(false);
    }
  };

  // ================= LOADING / ERROR UI =================
  if (loading)
    return (
      <div className="flex items-center justify-center min-h-screen text-gray-500 animate-pulse">
        Retrieving claim details...
      </div>
    );

  if (!claim)
    return (
      <div className="flex flex-col items-center justify-center min-h-screen">
        <p className="text-xl font-semibold text-gray-600">Claim not found</p>
        <button
          onClick={() => router.back()}
          className="mt-4 text-blue-600 hover:underline"
        >
          Go back
        </button>
      </div>
    );

  const { itemId: item, claimedBy: claimant, postedBy: poster } = claim;

  return (
    <div className="min-h-screen bg-gray-50 pb-12">
      {/* Header */}
      <div className="bg-white border-b sticky top-0 z-10">
        <div className="max-w-6xl mx-auto px-6 py-4 flex items-center justify-between">
          <button
            onClick={() => router.back()}
            className="flex items-center text-gray-600 hover:text-gray-900 transition"
          >
            <ArrowLeft size={20} className="mr-2" /> Back to Claims
          </button>
          <div className="flex gap-3">
            <span
              className={`px-3 py-1 rounded-full text-xs font-bold uppercase ${
                claim.status === "pending"
                  ? "bg-yellow-100 text-yellow-700"
                  : claim.status === "approved"
                    ? "bg-green-100 text-green-700"
                    : "bg-red-100 text-red-700"
              }`}
            >
              Claim: {claim.status}
            </span>
          </div>
        </div>
      </div>

      <main className="max-w-6xl mx-auto p-6 mt-4">
        <h1 className="text-2xl font-bold text-gray-800 mb-8">
          Review Request
        </h1>

        <div className="grid lg:grid-cols-3 gap-8">
          {/* Left Column: Item Details */}
          <div className="lg:col-span-2 space-y-6">
            <section className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
              <div className="p-6">
                <div className="flex items-center mb-4 text-blue-600">
                  <Package size={22} className="mr-2" />
                  <h2 className="text-lg font-bold">Item Information</h2>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  {/* Item Photos */}
                  {item?.photos?.length > 0 && (
                    <div className="space-y-3">
                      <p className="text-sm font-medium text-gray-500 uppercase tracking-wider">
                        Item Gallery
                      </p>
                      <div className="grid grid-cols-2 gap-2">
                        {item.photos.map((img, i) => (
                          <img
                            key={i}
                            src={`${img}`}
                            alt="Item"
                            className="aspect-square w-full object-cover rounded-lg border bg-gray-50"
                          />
                        ))}
                      </div>
                    </div>
                  )}

                  {/* Attributes */}
                  <div className="space-y-4">
                    <div>
                      <label className="text-xs text-gray-400 font-bold uppercase">
                        Item Name
                      </label>
                      <p className="text-gray-800 font-medium text-lg">
                        {item.itemName}
                      </p>
                    </div>
                    <div className="flex gap-10">
                      <div>
                        <label className="text-xs text-gray-400 font-bold uppercase">
                          Category
                        </label>
                        <p className="text-gray-700">{item.category}</p>
                      </div>
                      <div>
                        <label className="text-xs text-gray-400 font-bold uppercase">
                          Verified
                        </label>
                        <p
                          className={
                            item.isVerified
                              ? "text-green-600 font-bold"
                              : "text-gray-500"
                          }
                        >
                          {item.isVerified ? "✓ Yes" : "No"}
                        </p>
                      </div>
                    </div>
                    <div>
                      <label className="text-xs text-gray-400 font-bold uppercase">
                        Location
                      </label>
                      <p className="text-gray-700">{item.location}</p>
                    </div>
                    <div>
                      <label className="text-xs text-gray-400 font-bold uppercase">
                        Description
                      </label>
                      <p className="text-gray-600 text-sm leading-relaxed">
                        {item.description}
                      </p>
                    </div>
                  </div>
                </div>
              </div>
            </section>

            {/* Proof Section */}
            <section className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6">
              <div className="flex items-center mb-4 text-purple-600">
                <FileText size={22} className="mr-2" />
                <h2 className="text-lg font-bold">Claimant's Proof</h2>
              </div>
              <p className="bg-purple-50 text-purple-900 p-4 rounded-xl mb-6 italic border border-purple-100">
                "{claim.proofDescription}"
              </p>

              {claim.photos?.length > 0 && (
                <div>
                  <div className="flex items-center mb-3 text-gray-500 text-sm font-bold uppercase">
                    <ImageIcon size={16} className="mr-2" /> Proof Attachments
                  </div>
                  <div className="flex gap-4 overflow-x-auto pb-2">
                    {claim.photos.map((img, i) => {
                      const proofSrc =
                        typeof img === "string" && img.startsWith("http")
                          ? img
                          : `${BASE_URL}${String(img).startsWith("/") ? "" : "/uploads/"}${img}`;
                      return (
                        <img
                          key={i}
                          src={proofSrc}
                          alt="Proof"
                          className="h-32 w-48 shrink-0 object-cover rounded-xl border shadow-sm"
                        />
                      );
                    })}
                  </div>
                </div>
              )}
            </section>
          </div>

          {/* Right Column: User Sidebar */}
          <div className="space-y-6">
            <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6">
              <div className="flex items-center mb-6 text-gray-800">
                <User size={22} className="mr-2 text-green-600" />
                <h2 className="text-lg font-bold">Claimant Details</h2>
              </div>
              <div className="space-y-4">
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 rounded-full bg-green-100 text-green-700 flex items-center justify-center font-bold">
                    {claimant?.name?.charAt(0)}
                  </div>
                  <div>
                    <p className="font-bold text-gray-800">{claimant?.name}</p>
                    <p className="text-xs text-gray-500">{claimant?.email}</p>
                  </div>
                </div>
                <hr className="border-gray-50" />
                <div className="text-xs text-gray-400">
                  <p className="uppercase font-bold mb-1">Posted By</p>
                  <p className="text-gray-700 font-medium">{poster?.name}</p>
                  <p>{poster?.email}</p>
                </div>
              </div>
            </div>

            {/* Action Card */}
            <div className="bg-gray-100 rounded-2xl p-6 text-white shadow-xl">
              <h3 className="text-sm font-bold uppercase tracking-widest text-gray-400 mb-4">
                Final Decision
              </h3>
              <div className="grid gap-3">
                <button
                  onClick={() => handleAction("approveClaim", "approved")}
                  disabled={actionLoading || claim.status !== "pending"}
                  className={`w-full flex items-center justify-center ${
                    actionLoading
                      ? "bg-green-400 cursor-not-allowed"
                      : "bg-green-500 hover:bg-green-600"
                  } text-white font-bold py-3 rounded-xl transition-all shadow-lg shadow-green-900/20`}
                >
                  {actionLoading ? (
                    <Loader2 className="mr-2 animate-spin" size={20} />
                  ) : (
                    <CheckCircle size={20} className="mr-2" />
                  )}
                  Approve
                </button>
                <button
                  onClick={() => handleAction("rejectClaim", "rejected")}
                  disabled={actionLoading || claim.status !== "pending"}
                  className={`w-full flex items-center justify-center ${
                    actionLoading
                      ? "bg-red-400 cursor-not-allowed"
                      : "bg-red-500 hover:bg-red-600"
                  } text-white font-bold py-3 rounded-xl transition-all`}
                >
                  {actionLoading ? (
                    <Loader2 className="mr-2 animate-spin" size={20} />
                  ) : (
                    <XCircle size={20} className="mr-2" />
                  )}
                  Reject
                </button>
              </div>

              {actionResult && (
                <p className="text-sm text-center mt-3 text-gray-800 font-bold">
                  {actionResult}
                </p>
              )}
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default ClaimDetailsPage;
